// MaterialRegistry.hh
// Material registry for Geant4 simulation
// Provides centralized material access for DetectorConstruction and other classes

#ifndef MATERIAL_REGISTRY_HH
#define MATERIAL_REGISTRY_HH

#include "G4Material.hh"
#include "G4NistManager.hh"
#include <map>
#include <string>
#include <vector>

class MaterialRegistry {
public:
    static MaterialRegistry& Instance();

    // Get material by material_id from G4ModelIR
    G4Material* GetMaterial(const std::string& material_id) const;

    // Initialize registry from G4ModelIR materials
    void Initialize(const std::vector<std::pair<std::string, std::string>>& material_ids);

    // Check if material exists
    bool HasMaterial(const std::string& material_id) const;

private:
    MaterialRegistry();
    ~MaterialRegistry() = default;
    MaterialRegistry(const MaterialRegistry&) = delete;
    MaterialRegistry& operator=(const MaterialRegistry&) = delete;

    // Build material from G4ModelIR specification
    G4Material* BuildMaterial(const std::string& material_id);

    std::map<std::string, G4Material*> fMaterialMap;
    G4NistManager* fNistManager;
};

#endif // MATERIAL_REGISTRY_HH

// MaterialRegistry.cc
// Implementation of MaterialRegistry

#include "MaterialRegistry.hh"
#include "G4SystemOfUnits.hh"
#include "G4String.hh"

MaterialRegistry& MaterialRegistry::Instance() {
    static MaterialRegistry instance;
    return instance;
}

MaterialRegistry::MaterialRegistry() : fNistManager(G4NistManager::Instance()) {
}

void MaterialRegistry::Initialize(const std::vector<std::pair<std::string, std::string>>& material_ids) {
    // material_ids contains pairs of (material_id, nist_name)
    for (const auto& [material_id, nist_name] : material_ids) {
        if (fMaterialMap.find(material_id) == fMaterialMap.end()) {
            G4Material* material = fNistManager->FindOrBuildMaterial(nist_name);
            if (material) {
                fMaterialMap[material_id] = material;
            } else {
                G4Exception("MaterialRegistry::Initialize", "MaterialRegistry001", 
                           FatalException, 
                           ("Could not build material: " + nist_name).c_str());
            }
        }
    }
}

G4Material* MaterialRegistry::GetMaterial(const std::string& material_id) const {
    auto it = fMaterialMap.find(material_id);
    if (it != fMaterialMap.end()) {
        return it->second;
    }
    return nullptr;
}

bool MaterialRegistry::HasMaterial(const std::string& material_id) const {
    return fMaterialMap.find(material_id) != fMaterialMap.end();
}

G4Material* MaterialRegistry::BuildMaterial(const std::string& material_id) {
    // Currently not used as we initialize all materials at once
    // Could be extended for custom materials
    return nullptr;
}

// PlacementManager.hh
// Placement manager for Geant4 simulation
// Manages physical volume placements and provides volume accessors

#ifndef PLACEMENT_MANAGER_HH
#define PLACEMENT_MANAGER_HH

#include "G4VPhysicalVolume.hh"
#include "G4LogicalVolume.hh"
#include "G4PVPlacement.hh"
#include "G4RotationMatrix.hh"
#include "G4ThreeVector.hh"
#include "G4String.hh"
#include <map>
#include <vector>

class PlacementManager {
public:
    static PlacementManager& Instance();

    // Initialize with world physical volume
    void Initialize(G4VPhysicalVolume* world_pv);

    // Place a volume in the geometry hierarchy
    G4VPhysicalVolume* PlaceVolume(const G4String& component_id,
                                   G4LogicalVolume* logical_volume,
                                   const G4String& mother_component_id,
                                   const G4ThreeVector& position,
                                   G4RotationMatrix* rotation = nullptr,
                                   G4bool check_overlaps = true);

    // Get physical volume by component_id
    G4VPhysicalVolume* GetPhysicalVolume(const G4String& component_id) const;

    // Get logical volume by component_id
    G4LogicalVolume* GetLogicalVolume(const G4String& component_id) const;

    // Get world physical volume
    G4VPhysicalVolume* GetWorldVolume() const;

private:
    PlacementManager();
    ~PlacementManager() = default;
    PlacementManager(const PlacementManager&) = delete;
    PlacementManager& operator=(const PlacementManager&) = delete;

    // Store mappings
    std::map<std::string, G4VPhysicalVolume*> fPhysicalVolumeMap;
    std::map<std::string, G4LogicalVolume*> fLogicalVolumeMap;
    G4VPhysicalVolume* fWorldVolume;
};

#endif // PLACEMENT_MANAGER_HH

// PlacementManager.cc
// Implementation of PlacementManager

#include "PlacementManager.hh"
#include "G4SystemOfUnits.hh"
#include "G4Box.hh"
#include "G4PVPlacement.hh"
#include "G4RotationMatrix.hh"
#include "G4Exception.hh"

PlacementManager& PlacementManager::Instance() {
    static PlacementManager instance;
    return instance;
}

PlacementManager::PlacementManager() : fWorldVolume(nullptr) {
}

void PlacementManager::Initialize(G4VPhysicalVolume* world_pv) {
    fWorldVolume = world_pv;
    if (!fWorldVolume) {
        G4Exception("PlacementManager::Initialize", "PlacementManager001", 
                   FatalException, 
                   "World physical volume is null");
    }

    // Register world volume with component_id "world"
    fPhysicalVolumeMap["world"] = fWorldVolume;
    fLogicalVolumeMap["world"] = fWorldVolume->GetLogicalVolume();
}

G4VPhysicalVolume* PlacementManager::PlaceVolume(const G4String& component_id,
                                                  G4LogicalVolume* logical_volume,
                                                  const G4String& mother_component_id,
                                                  const G4ThreeVector& position,
                                                  G4RotationMatrix* rotation,
                                                  G4bool check_overlaps) {
    // Check if component already placed
    if (fPhysicalVolumeMap.find(component_id) != fPhysicalVolumeMap.end()) {
        G4Exception("PlacementManager::PlaceVolume", "PlacementManager002", 
                   JustWarning, 
                   ("Component " + component_id + " already placed").c_str());
        return fPhysicalVolumeMap[component_id];
    }

    // Get mother logical volume
    G4LogicalVolume* mother_logical = nullptr;
    if (mother_component_id.empty() || mother_component_id == "world") {
        mother_logical = fLogicalVolumeMap["world"];
    } else {
        auto it = fLogicalVolumeMap.find(mother_component_id);
        if (it != fLogicalVolumeMap.end()) {
            mother_logical = it->second;
        } else {
            G4Exception("PlacementManager::PlaceVolume", "PlacementManager003", 
                       FatalException, 
                       ("Mother component " + mother_component_id + " not found").c_str());
        }
    }

    // Create physical volume
    G4PVPlacement* physical_volume = new G4PVPlacement(
        rotation,
        position,
        logical_volume,
        component_id,
        mother_logical,
        false,           // pMany
        0,               // copyNo
        check_overlaps   // surfCheck
    );

    // Store mappings
    fPhysicalVolumeMap[component_id] = physical_volume;
    fLogicalVolumeMap[component_id] = logical_volume;

    return physical_volume;
}

G4VPhysicalVolume* PlacementManager::GetPhysicalVolume(const G4String& component_id) const {
    auto it = fPhysicalVolumeMap.find(component_id);
    if (it != fPhysicalVolumeMap.end()) {
        return it->second;
    }
    return nullptr;
}

G4LogicalVolume* PlacementManager::GetLogicalVolume(const G4String& component_id) const {
    auto it = fLogicalVolumeMap.find(component_id);
    if (it != fLogicalVolumeMap.end()) {
        return it->second;
    }
    return nullptr;
}

G4VPhysicalVolume* PlacementManager::GetWorldVolume() const {
    return fWorldVolume;
}

