  G4String fOutputDir;

  // Accumulated 3D grid across entire run
  std::vector<GridBin> fGrid;

  // Per-event records
  std::vector<EventRecord> fEventRecords;

  // Current event accumulators
  G4double fCurrentEdep = 0.0;
  G4double fCurrentDose = 0.0;

  // Timing
  G4double fRunStartTime = 0.0;
