  ofs << "  \"physics_list\": \"FTFP_BERT\"," << std::endl;
  ofs << "  \"detector\": \"RadAgent Silicon Detector\"," << std::endl;
  ofs << "  \"scoring\": \"energy_dose_3d\"" << std::endl;
  ofs << "}" << std::endl;

